mapper.select:
/* 코드 그룹 목록 조회 codes.selectGroupList */ SELECT CODE_GRP_ID , CODE_GRP_NM , DESCRIPTION , USE_YN , CREATE_DT FROM TB_CODE_GRP WHERE 1=1
AND USE_YN = #{useYn}
ORDER BY CREATE_DT DESC

/* 코드 목록 조회 codes.selectCodeList */ SELECT CODE_GRP_ID , CODE_ID , CODE_NM , SORT_ORD , USE_YN , DESCRIPTION FROM TB_CODE WHERE 1=1
AND CODE_GRP_ID = #{codeGrpId}
AND USE_YN = #{useYn}
ORDER BY CODE_GRP_ID, SORT_ORD, CODE_ID

/* 코드 그룹 내 최대 정렬순서 조회 codes.selectMaxSortOrd */
SELECT IFNULL(MAX(SORT_ORD), 0)
FROM TB_CODE
WHERE CODE_GRP_ID = #{codeGrpId}

mapper.insert:
/* 코드 그룹 등록/수정 codes.insertGroup */
INSERT INTO TB_CODE_GRP (
    CODE_GRP_ID
    , CODE_GRP_NM
    , DESCRIPTION
    , USE_YN
    , CREATE_DT
) VALUES (
    #{codeGrpId}
    , #{codeGrpNm}
    , #{description}
    , #{useYn, jdbcType=VARCHAR}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    CODE_GRP_NM = VALUES(CODE_GRP_NM)
    , DESCRIPTION = VALUES(DESCRIPTION)
    , USE_YN = VALUES(USE_YN)

/* 코드 등록/수정 codes.insertCode */
INSERT INTO TB_CODE (
    CODE_GRP_ID
    , CODE_ID
    , CODE_NM
    , SORT_ORD
    , USE_YN
    , DESCRIPTION
) VALUES (
    #{codeGrpId}
    , #{codeId}
    , #{codeNm}
    , #{sortOrd, jdbcType=INTEGER}
    , #{useYn, jdbcType=VARCHAR}
    , #{description}
)
ON DUPLICATE KEY UPDATE
    CODE_NM = VALUES(CODE_NM)
    , SORT_ORD = VALUES(SORT_ORD)
    , USE_YN = VALUES(USE_YN)
    , DESCRIPTION = VALUES(DESCRIPTION)
